async (page) => {
  // Try death respawn - look for respawn button or use warp
  await page.evaluate(() => {
    // Try clicking respawn button
    const respawn = document.getElementById('respawn') || 
                    document.querySelector('.respawn-button') ||
                    document.querySelector('[data-action="respawn"]');
    if (respawn) { respawn.click(); return 'clicked respawn'; }

    // Try warp to Mudwich
    window.game.menu.warp.show();
    setTimeout(() => document.getElementById('warp0')?.click(), 500);
    return 'tried warp';
  });
  await page.waitForTimeout(3000);

  const state = await page.evaluate(() => {
    const g = window.__latestGameState;
    return { pos: g.player_position, hp: g.player_stats.hp, dead: g.ui_state.is_dead };
  });
  return JSON.stringify(state);
}
